import java.util.HashSet;
import java.util.Map;
import java.util.Set;
import java.util.stream.Collectors;

public class SleutelGegevensImp extends HasPropertiesImp implements SleutelGegevens {

    protected Opper paragonOpper;

    private LocalDate actualFrom;
    private LocalDate actualTo;
    private Set<Sleutel<?>> sleutels;
    private Map<Class<? extends Sleutel>, Sleutel<?>> classToSleutelMap;
    private Set<Opper> oppers;

    private Collection<LoonElement> gegevensElementen;
    private PrestatieSamenvattingImp gegevensPrestatieSamenvatting;

    protected SleutelGegevensImp(Opper opper, Set<Sleutel<?>> sleutels) {
        this.sleutels = sleutels;
        classToSleutelMap = sleutels == null ? new HashMap<>() : sleutels.stream().collect(Collectors.toMap(Sleutel::getClass, x -> x));
        this.oppers = new HashSet<>();
        oppers.add(opper);
        this.paragonOpper = opper;
        this.actualFrom = opper.getActualFrom();
        this.actualTo = opper.getActualTo();
    }

    @Override
    public LocalDateInterval getActualInterval() {
        return new LocalDateInterval(actualFrom, actualTo);
    }

    @Override
    public LocalDate getActualFrom() {
        return actualFrom;
    }

    @Override
    public LocalDate getActualTo() {
        return actualTo;
    }

    @Override
    public Set<Opper> getOppers() {
        return oppers;
    }

    public void merge(Opper opper) {
        oppers.add(opper);
        actualFrom = actualFrom.isBefore(opper.getActualFrom()) ? actualFrom : opper.getActualFrom();
        actualTo = actualTo.isAfter(opper.getActualTo()) ? actualTo : opper.getActualTo();
    }

    @Override
    public boolean match(Opper opper) {
        boolean match = true;
        for (Sleutel<?> sleutel : sleutels) {
            match = sleutel.equalsVoorSleutel(opper, paragonOpper);
            if (!match) {
                break;
            }
        }
        return match;
    }

    public <T> T getValueByClass(Sleutel<T> sleutel) {
        if (sleutels == null) {
            return sleutel.getValue(paragonOpper);
        } else if (classToSleutelMap.containsKey(sleutel.getClass())) {
            Sleutel<T> sleutelFound = (Sleutel<T>) classToSleutelMap.get(sleutel.getClass());
            return sleutelFound.getValue(paragonOpper);
        } else {
            throw new IsGeenSleutelException(sleutel);
        }
    }

    @Override
    public <T> T getValue(Sleutel<T> sleutel) {
        if (sleutels.contains(sleutel)) {
            return sleutel.getValue(paragonOpper);
        } else {
            throw new IsGeenSleutelException(sleutel);
        }
    }

    @Override
    public WerkgeversCategorie getWerkgeversCategorie() {
        return getValue(SleutelWerkgeversCategorie.INSTANCE);
    }

    @Override
    public DmfapplWnkengetal getWerknemersKengetal() {
        return getValue(SleutelWerknemersKengetal.INSTANCE);
    }

    @Override
    public Hoedanigheid getHoedanigheid() {
        return paragonOpper.getOpdracht().getHoedanigheid();
    }

    @Override
    public Rekenwijze getRekenWijze() {
        return getValue(SleutelRekenWijze.INSTANCE);
    }

    @Override
    public DmfapplStatuutDmfappl getStatuutDmfappl() {
        return getValue(SleutelStatuutDmfappl.INSTANCE);
    }

    @Override
    public RszppoKategorie getCategorie() {
        return getValueByClass(SleutelCategorie.INSTANCE);
    }

    @Override
    public Money getJaarWedde() {
        return getValue(SleutelJaarWedde.INSTANCE);
    }

    @Override
    public Money getSalarisverhoging() {
        return getValue(SleutelSalarisverhoging.INSTANCE);
    }

    @Override
    public BigDecimal getAfwijkendeIndex() {
        return getValue(SleutelAfwijkendeIndex.INSTANCE);
    }

    @Override
    public Collection<LoonElement> getOpperElementen(LoonElementManager manager) {
        if (gegevensElementen == null) {
            gegevensElementen = manager.getOpperElementen(oppers);
        }
        return gegevensElementen;
    }

    @Override
    public Set<Vergoeding> getVergoedingen() {
        return getValue(SleutelVergoedingen.INSTANCE);
    }

    @Override
    public Integer getUurNoemer() {
        return getValue(SleutelUurNoemer.INSTANCE);
    }

    @Override
    public Pensioenstelsel getPensioenStelsel() {
        return getValue(SleutelPensioenStelsel.INSTANCE);
    }

    @Override
    public PvhVorming getPrestatieVerhoudingVorming() {
        return getValue(SleutelPrestatieVerhoudingVorming.INSTANCE);
    }

    @Override
    public BigDecimal getTellerPrestatieVerhouding() {
        return getValue(SleutelTellerPrestatieVerhouding.INSTANCE);
    }

    @Override
    public BigDecimal getNoemerPrestatieVerhouding() {
        return getValue(SleutelNoemerPrestatieVerhouding.INSTANCE);
    }

    @Override
    public BigDecimal getAanstelling() {
        return getValue(SleutelAanstelling.INSTANCE);
    }

    @Override
    public Integer getAfwezigheidsCode() {
        return getValue(SleutelAfwezigheidsCode.INSTANCE);
    }

    @Override
    public Integer getAfwezigheidsExtensie() {
        return getValue(SleutelAfwezigheidsExtensie.INSTANCE);
    }

    @Override
    public BigDecimal getAfwezigheidsUren() {
        return getValue(SleutelAfwezigheidsUren.INSTANCE);
    }

    @Override
    public BigDecimal getMaatman() {
        return getValue(SleutelMaatman.INSTANCE);
    }

    @Override
    public Jaar2maand getJaarNaarMaand() {
        return getValue(SleutelJaarNaarMaand.INSTANCE);
    }

    @Override
    public Integer getRszDagenStelsel() {
        return getValue(SleutelRszDagenStelsel.INSTANCE);
    }

    @Override
    public VrijstelPens2 getVrijstellingTweedePensioenpijler() {
        return getValue(SleutelVrijstellingTweedePensioenpijler.INSTANCE);
    }

    @Override
    public DmfapplCodeVermin getVerminderingsCodeWerkbonus() {
        return getValue(SleutelVerminderingsCodeWerkbonus.INSTANCE);
    }

    @Override
    public DmfapplCodeVermin getVerminderingsCode() {
        return getValue(SleutelVerminderingsCode.INSTANCE);
    }

    @Override
    public Integer getTypeLeerling() {
        return getValue(SleutelTypeLeerling.INSTANCE);
    }

    @Override
    public Set<AfwezigheidBO> getAfwezighedenInvoerModule() {
        return getValue(SleutelAfwezighedenInvoerModule.INSTANCE);
    }

    @Override
    public Integer getMaatregelingReorganisatieArbeidsTijd() {
        return getValue(SleutelMaatregelingReorganisatieArbeidsTijd.INSTANCE);
    }

    @Override
    public Integer getMaatregelingReorganisatieArbeidsTijd2() {
        return getValue(SleutelMaatregelingReorganisatieArbeidsTijd2.INSTANCE);
    }

    @Override
    public Dienstverband getDienstverband() {
        return getValue(SleutelDienstverband.INSTANCE);
    }

    @Override
    public Maandverwerking getMaandverwerking() {
        return getValue(SleutelMaandverwerking.INSTANCE);
    }

    @Override
    public BigDecimal getAfwijkendDisponibiliteit60Percentage() {
        return getValue(SleutelAfwijkendDisponibiliteit60Percentage.INSTANCE);
    }

    @Override
    public String getNaceCode() {
        return getValue(SleutelNaceCode.INSTANCE);
    }

    @Override
    public boolean isOnregelmatigPerPrestatieOfPerUur() {
        return RekenTools.isOnregelmatigPerPrestatieOfPerUur(getMaatman());
    }

    @Override
    public boolean isAfwijkendeIndexFederaal() {
        return Boolean.TRUE.equals(getValue(SleutelAfwijkendeIndexFederaal.INSTANCE));
    }

    @Override
    public String toString() {
        StringBuilder builder = new StringBuilder();
        builder.append(getClass().getSimpleName()).append('[');
        for (Opper opper : oppers) {
            builder.append(opper.getId()).append(',');
        }
        builder.append("],actual[").append(actualFrom).append(',').append(actualTo).append(']');
        return builder.toString();
    }

    @Override
    public PrestatieSamenvattingImp getPrestatieSamenvatting(RekenContext context) {
        if (gegevensPrestatieSamenvatting == null) {
            gegevensPrestatieSamenvatting = new PrestatieSamenvattingImp();

            for (Opper opper : getOppers()) {
                PrestatieSamenvattingImp samenvatting = context.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_KEY, opper);
                gegevensPrestatieSamenvatting = gegevensPrestatieSamenvatting.addPrestatieSamenvatting(samenvatting);
            }
        }
        return gegevensPrestatieSamenvatting;
    }

    @Override
    public Opdracht getOpdracht() {
        return paragonOpper.getOpdracht();
    }

}
